// === Types ===

export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, unknown>[];
  headers: string[];
  errors: CSVError[];
  filter: (predicate: (row: Record<string, unknown>) => boolean) => Record<string, unknown>[];
  sum: (column: string) => number;
  average: (column: string) => number;
  count: () => number;
  groupBy: (column: string) => Map<unknown, Record<string, unknown>[]>;
}

// === Field-level type coercion ===

function coerceValue(raw: string): unknown {
  // Null / empty
  if (raw === "" || raw === "null" || raw === "NULL") {
    return null;
  }

  // Boolean (case-insensitive)
  if (raw.toLowerCase() === "true") return true;
  if (raw.toLowerCase() === "false") return false;

  // Number – must be the *entire* trimmed string and a valid finite number.
  // We reject strings that are empty after trim, or consist of only whitespace,
  // or use JS quirks like "Infinity", "0x1f", etc.
  const trimmed = raw.trim();
  if (trimmed !== "" && !isNaN(Number(trimmed)) && isFinite(Number(trimmed))) {
    // Guard against things like "  " mapping to 0
    // Also reject hex / octal / binary literals that Number() would accept
    if (/^[+-]?(\d+\.?\d*|\.\d+)([eE][+-]?\d+)?$/.test(trimmed)) {
      return Number(trimmed);
    }
  }

  return raw;
}

// === Low-level line tokeniser (handles quoted fields) ===

function parseRow(
  line: string,
  delimiter: string,
  quote: string
): string[] {
  const fields: string[] = [];
  let i = 0;
  const len = line.length;

  while (i <= len) {
    if (i === len) {
      // Trailing delimiter produced an empty field
      fields.push("");
      break;
    }

    if (line[i] === quote) {
      // --- quoted field ---
      let value = "";
      i++; // skip opening quote
      while (i < len) {
        if (line[i] === quote) {
          if (i + 1 < len && line[i + 1] === quote) {
            // Escaped quote
            value += quote;
            i += 2;
          } else {
            // Closing quote
            i++; // skip closing quote
            break;
          }
        } else {
          value += line[i];
          i++;
        }
      }
      fields.push(value);
      // After a closing quote we expect either a delimiter or end of line
      if (i < len && line[i] === delimiter) {
        i++; // skip delimiter
        // If the delimiter is the very last character, there's an empty trailing field
        if (i === len) {
          fields.push("");
        }
      }
    } else {
      // --- unquoted field ---
      const nextDelim = line.indexOf(delimiter, i);
      if (nextDelim === -1) {
        fields.push(line.substring(i));
        break;
      } else {
        fields.push(line.substring(i, nextDelim));
        i = nextDelim + 1;
        // Trailing delimiter → empty field
        if (i === len) {
          fields.push("");
        }
      }
    }
  }

  return fields;
}

// === Split input into logical lines (respecting quoted fields that span lines) ===

function splitLogicalLines(
  input: string,
  lineSeparator: string,
  quote: string
): string[] {
  const lines: string[] = [];
  let current = "";
  let insideQuotes = false;

  let i = 0;
  const len = input.length;
  const sepLen = lineSeparator.length;

  while (i < len) {
    // Check for quote toggle
    if (input[i] === quote) {
      insideQuotes = !insideQuotes;
      current += input[i];
      i++;
      continue;
    }

    // Check for line separator (only when not inside quotes)
    if (
      !insideQuotes &&
      input.substring(i, i + sepLen) === lineSeparator
    ) {
      lines.push(current);
      current = "";
      i += sepLen;
      continue;
    }

    current += input[i];
    i++;
  }

  // Push last segment (if non-empty)
  if (current.length > 0) {
    lines.push(current);
  }

  return lines;
}

// === Main entry point ===

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ",";
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator ?? "\n";

  const errors: CSVError[] = [];

  // Edge case: completely empty / whitespace-only input
  const trimmed = input.trim();
  if (trimmed === "") {
    return buildResult([], [], errors);
  }

  // Split into logical lines (handling multi-line quoted fields)
  const lines = splitLogicalLines(trimmed, lineSeparator, quote);

  if (lines.length === 0) {
    return buildResult([], [], errors);
  }

  // First line = headers
  const headers = parseRow(lines[0], delimiter, quote);

  // Parse data rows
  const rows: Record<string, unknown>[] = [];

  for (let idx = 1; idx < lines.length; idx++) {
    const line = lines[idx];

    // Skip completely empty lines
    if (line.trim() === "") continue;

    try {
      const fields = parseRow(line, delimiter, quote);

      if (fields.length !== headers.length) {
        errors.push({
          row: idx + 1, // 1-based, header is row 1
          message: `Expected ${headers.length} fields but got ${fields.length}`,
        });
        // Still include the row with best-effort mapping
        const row: Record<string, unknown> = {};
        for (let c = 0; c < headers.length; c++) {
          row[headers[c]] = c < fields.length ? coerceValue(fields[c]) : null;
        }
        // Extra fields beyond headers are silently ignored (error already recorded)
        rows.push(row);
        continue;
      }

      const row: Record<string, unknown> = {};
      for (let c = 0; c < headers.length; c++) {
        row[headers[c]] = coerceValue(fields[c]);
      }
      rows.push(row);
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : String(err);
      errors.push({
        row: idx + 1,
        message: `Parse error: ${msg}`,
      });
    }
  }

  return buildResult(rows, headers, errors);
}

// === Build the rich result object with helper methods ===

function buildResult(
  rows: Record<string, unknown>[],
  headers: string[],
  errors: CSVError[]
): CSVResult {
  return {
    rows,
    headers,
    errors,

    filter(predicate: (row: Record<string, unknown>) => boolean): Record<string, unknown>[] {
      return rows.filter(predicate);
    },

    sum(column: string): number {
      let total = 0;
      for (const row of rows) {
        const val = row[column];
        if (typeof val === "number") {
          total += val;
        }
      }
      return total;
    },

    average(column: string): number {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const val = row[column];
        if (typeof val === "number") {
          total += val;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<unknown, Record<string, unknown>[]> {
      const map = new Map<unknown, Record<string, unknown>[]>();
      for (const row of rows) {
        const key = row[column];
        if (!map.has(key)) {
          map.set(key, []);
        }
        map.get(key)!.push(row);
      }
      return map;
    },
  };
}

import { parseCSV, CSVResult } from "./csv-parser";

// ── Tiny test harness (no framework) ─────────────────────────────────

let passed = 0;
let failed = 0;
const failures: string[] = [];

function assert(condition: boolean, msg: string): void {
  if (!condition) {
    throw new Error(`Assertion failed: ${msg}`);
  }
}

function assertEqual(actual: unknown, expected: unknown, msg: string): void {
  const a = JSON.stringify(actual);
  const e = JSON.stringify(expected);
  if (a !== e) {
    throw new Error(`${msg}\n  expected: ${e}\n  actual:   ${a}`);
  }
}

function assertClose(actual: number, expected: number, epsilon: number, msg: string): void {
  if (Math.abs(actual - expected) > epsilon) {
    throw new Error(`${msg}\n  expected ≈${expected}, got ${actual}`);
  }
}

function test(name: string, fn: () => void): void {
  try {
    fn();
    passed++;
    console.log(`  ✅ ${name}`);
  } catch (err: unknown) {
    failed++;
    const msg = err instanceof Error ? err.message : String(err);
    failures.push(`${name}: ${msg}`);
    console.log(`  ❌ ${name}`);
    console.log(`     ${msg}`);
  }
}

// ── Tests ────────────────────────────────────────────────────────────

console.log("\n=== Basic Parsing ===");

test("parses simple CSV into array of objects", () => {
  const csv = "name,age,city\nAlice,30,NYC\nBob,25,LA";
  const result = parseCSV(csv);
  assertEqual(result.headers, ["name", "age", "city"], "headers");
  assertEqual(result.rows.length, 2, "row count");
  assertEqual(result.rows[0], { name: "Alice", age: 30, city: "NYC" }, "row 0");
  assertEqual(result.rows[1], { name: "Bob", age: 25, city: "LA" }, "row 1");
  assertEqual(result.errors.length, 0, "no errors");
});

test("first row becomes headers", () => {
  const csv = "h1,h2,h3\na,b,c";
  const result = parseCSV(csv);
  assertEqual(result.headers, ["h1", "h2", "h3"], "headers match first row");
});

test("preserves whitespace in unquoted fields", () => {
  const csv = "a,b\n  hello ,  world ";
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["a"], "  hello ", "leading/trailing spaces kept");
  assertEqual(result.rows[0]["b"], "  world ", "leading/trailing spaces kept");
});

console.log("\n=== Quoted Fields ===");

test("handles quoted fields", () => {
  const csv = 'name,bio\n"Alice","Likes coding"';
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["name"], "Alice", "quoted name");
  assertEqual(result.rows[0]["bio"], "Likes coding", "quoted bio");
});

test("handles commas inside quoted fields", () => {
  const csv = 'name,address\n"Smith, John","123 Main St, Apt 4"';
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["name"], "Smith, John", "comma in name");
  assertEqual(result.rows[0]["address"], "123 Main St, Apt 4", "comma in address");
});

test("handles newlines inside quoted fields", () => {
  const csv = 'name,bio\n"Alice","Line1\nLine2"\n"Bob","Simple"';
  const result = parseCSV(csv);
  assertEqual(result.rows.length, 2, "two rows");
  assertEqual(result.rows[0]["bio"], "Line1\nLine2", "newline preserved in quoted field");
  assertEqual(result.rows[1]["bio"], "Simple", "second row ok");
});

console.log("\n=== Escaped Quotes ===");

test("handles escaped double quotes inside quoted fields", () => {
  const csv = 'name,quote\n"Alice","She said ""hello"""';
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["quote"], 'She said "hello"', "escaped quotes");
});

test("handles field that is just escaped quotes", () => {
  const csv = 'a\n""""""';
  const result = parseCSV(csv);
  // """""" → content between outer quotes is """" → two escaped quotes → ""
  assertEqual(result.rows[0]["a"], '""', "double-escaped");
});

test("handles empty quoted field", () => {
  const csv = 'a,b\n"",value';
  const result = parseCSV(csv);
  // Empty quoted field → empty string → coerced to null
  assertEqual(result.rows[0]["a"], null, "empty quoted field → null");
});

console.log("\n=== Custom Delimiters ===");

test("supports tab delimiter", () => {
  const csv = "name\tage\nAlice\t30";
  const result = parseCSV(csv, { delimiter: "\t" });
  assertEqual(result.headers, ["name", "age"], "headers");
  assertEqual(result.rows[0], { name: "Alice", age: 30 }, "row");
});

test("supports semicolon delimiter", () => {
  const csv = "a;b;c\n1;2;3";
  const result = parseCSV(csv, { delimiter: ";" });
  assertEqual(result.rows[0], { a: 1, b: 2, c: 3 }, "semicolon delimited");
});

test("supports pipe delimiter", () => {
  const csv = "x|y\nhello|world";
  const result = parseCSV(csv, { delimiter: "|" });
  assertEqual(result.rows[0], { x: "hello", y: "world" }, "pipe delimited");
});

test("supports custom quote character (single quote)", () => {
  const csv = "name,val\n'hello, world',42";
  const result = parseCSV(csv, { quote: "'" });
  assertEqual(result.rows[0]["name"], "hello, world", "single-quote quoting");
  assertEqual(result.rows[0]["val"], 42, "numeric after single-quoted field");
});

test("supports custom line separator (CRLF)", () => {
  const csv = "a,b\r\n1,2\r\n3,4";
  const result = parseCSV(csv, { lineSeparator: "\r\n" });
  assertEqual(result.rows.length, 2, "two rows");
  assertEqual(result.rows[0], { a: 1, b: 2 }, "row 0");
  assertEqual(result.rows[1], { a: 3, b: 4 }, "row 1");
});

test("supports custom multi-char line separator", () => {
  const csv = "a,b||1,2||3,4";
  const result = parseCSV(csv, { lineSeparator: "||" });
  assertEqual(result.rows.length, 2, "two rows");
  assertEqual(result.rows[0], { a: 1, b: 2 }, "row 0");
});

console.log("\n=== Type Coercion ===");

test("coerces integers", () => {
  const csv = "val\n0\n42\n-7\n+3";
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["val"], 0, "zero");
  assertEqual(result.rows[1]["val"], 42, "positive int");
  assertEqual(result.rows[2]["val"], -7, "negative int");
  assertEqual(result.rows[3]["val"], 3, "explicit positive");
});

test("coerces floats", () => {
  const csv = "val\n3.14\n-0.5\n.25\n1e3\n2.5e-1";
  const result = parseCSV(csv);
  assertClose(result.rows[0]["val"] as number, 3.14, 0.001, "pi-ish");
  assertClose(result.rows[1]["val"] as number, -0.5, 0.001, "negative float");
  assertClose(result.rows[2]["val"] as number, 0.25, 0.001, "leading-dot float");
  assertEqual(result.rows[3]["val"], 1000, "scientific notation");
  assertClose(result.rows[4]["val"] as number, 0.25, 0.001, "negative exponent");
});

test("coerces booleans (case-insensitive)", () => {
  const csv = "val\ntrue\nfalse\nTRUE\nFALSE\nTrue\nFalse";
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["val"], true, "true");
  assertEqual(result.rows[1]["val"], false, "false");
  assertEqual(result.rows[2]["val"], true, "TRUE");
  assertEqual(result.rows[3]["val"], false, "FALSE");
  assertEqual(result.rows[4]["val"], true, "True");
  assertEqual(result.rows[5]["val"], false, "False");
});

test("coerces null values", () => {
  const csv = "a,b,c\nnull,NULL,";
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["a"], null, "null");
  assertEqual(result.rows[0]["b"], null, "NULL");
  assertEqual(result.rows[0]["c"], null, "empty string → null");
});

test("leaves plain strings as strings", () => {
  const csv = "val\nhello\nworld\nNULLx\n123abc";
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["val"], "hello", "string");
  assertEqual(result.rows[1]["val"], "world", "string");
  assertEqual(result.rows[2]["val"], "NULLx", "not null");
  assertEqual(result.rows[3]["val"], "123abc", "not number");
});

test("does not coerce hex/octal/binary as numbers", () => {
  const csv = "val\n0x1f\n0o17\n0b1010";
  const result = parseCSV(csv);
  assertEqual(typeof result.rows[0]["val"], "string", "hex stays string");
  assertEqual(typeof result.rows[1]["val"], "string", "octal stays string");
  assertEqual(typeof result.rows[2]["val"], "string", "binary stays string");
});

console.log("\n=== Error Handling ===");

test("collects error for row with too few fields", () => {
  const csv = "a,b,c\n1,2\n4,5,6";
  const result = parseCSV(csv);
  assertEqual(result.errors.length, 1, "one error");
  assertEqual(result.errors[0].row, 2, "error on row 2");
  assert(result.errors[0].message.includes("2"), "mentions field count");
  assert(result.errors[0].message.includes("3"), "mentions expected count");
  // Row is still included with null for missing field
  assertEqual(result.rows[0]["c"], null, "missing field → null");
  assertEqual(result.rows.length, 2, "both rows included");
});

test("collects error for row with too many fields", () => {
  const csv = "a,b\n1,2,3\n4,5";
  const result = parseCSV(csv);
  assertEqual(result.errors.length, 1, "one error");
  assertEqual(result.errors[0].row, 2, "error on row 2");
  // Row is still included (extra fields ignored)
  assertEqual(result.rows.length, 2, "both rows included");
});

test("multiple malformed rows each produce errors", () => {
  const csv = "a,b\n1\n2\n3,4";
  const result = parseCSV(csv);
  assertEqual(result.errors.length, 2, "two errors");
  assertEqual(result.errors[0].row, 2, "first error row");
  assertEqual(result.errors[1].row, 3, "second error row");
  assertEqual(result.rows.length, 3, "all rows still included");
});

test("parser does not crash on malformed input", () => {
  const csv = 'a,b\n"unterminated quote,oops\nnext,row';
  // Should not throw
  const result = parseCSV(csv);
  assert(result.rows.length >= 0, "did not crash");
});

console.log("\n=== Filter ===");

test("filter returns matching rows", () => {
  const csv = "name,age\nAlice,30\nBob,25\nCharlie,35";
  const result = parseCSV(csv);
  const young = result.filter((r) => (r.age as number) < 30);
  assertEqual(young.length, 1, "one match");
  assertEqual(young[0]["name"], "Bob", "Bob is young");
});

test("filter with no matches returns empty array", () => {
  const csv = "val\n1\n2\n3";
  const result = parseCSV(csv);
  const none = result.filter((r) => (r.val as number) > 100);
  assertEqual(none.length, 0, "no matches");
});

test("filter with all matches returns all rows", () => {
  const csv = "val\n1\n2\n3";
  const result = parseCSV(csv);
  const all = result.filter(() => true);
  assertEqual(all.length, 3, "all match");
});

test("filter can use string comparison", () => {
  const csv = "name,city\nAlice,NYC\nBob,LA\nCharlie,NYC";
  const result = parseCSV(csv);
  const nyc = result.filter((r) => r.city === "NYC");
  assertEqual(nyc.length, 2, "two in NYC");
});

console.log("\n=== Aggregation: sum ===");

test("sum of numeric column", () => {
  const csv = "item,price\napple,1.5\nbanana,2.0\ncherry,3.5";
  const result = parseCSV(csv);
  assertClose(result.sum("price"), 7.0, 0.001, "sum of prices");
});

test("sum ignores non-numeric values", () => {
  const csv = "val\n10\nhello\n20\nnull";
  const result = parseCSV(csv);
  assertEqual(result.sum("val"), 30, "sum skips non-numbers");
});

test("sum of non-existent column is 0", () => {
  const csv = "a\n1\n2";
  const result = parseCSV(csv);
  assertEqual(result.sum("z"), 0, "missing column → 0");
});

test("sum with empty rows is 0", () => {
  const csv = "a";
  const result = parseCSV(csv);
  assertEqual(result.sum("a"), 0, "no data rows → 0");
});

console.log("\n=== Aggregation: average ===");

test("average of numeric column", () => {
  const csv = "val\n10\n20\n30";
  const result = parseCSV(csv);
  assertClose(result.average("val"), 20, 0.001, "average");
});

test("average ignores non-numeric values", () => {
  const csv = "val\n10\nhello\n20";
  const result = parseCSV(csv);
  // Only 10 and 20 → average 15
  assertClose(result.average("val"), 15, 0.001, "average skips non-numbers");
});

test("average of empty dataset is 0", () => {
  const csv = "val";
  const result = parseCSV(csv);
