// =============================================
// csv-parser.ts (transpiled)
// =============================================

function coerceValue(raw) {
  if (raw === "" || raw === "null" || raw === "NULL") {
    return null;
  }
  if (raw.toLowerCase() === "true") return true;
  if (raw.toLowerCase() === "false") return false;
  var trimmed = raw.trim();
  if (trimmed !== "" && !isNaN(Number(trimmed)) && isFinite(Number(trimmed))) {
    if (/^[+-]?(\d+\.?\d*|\.\d+)([eE][+-]?\d+)?$/.test(trimmed)) {
      return Number(trimmed);
    }
  }
  return raw;
}

function parseRow(line, delimiter, quote) {
  var fields = [];
  var i = 0;
  var len = line.length;
  while (i <= len) {
    if (i === len) {
      fields.push("");
      break;
    }
    if (line[i] === quote) {
      var value = "";
      i++;
      while (i < len) {
        if (line[i] === quote) {
          if (i + 1 < len && line[i + 1] === quote) {
            value += quote;
            i += 2;
          } else {
            i++;
            break;
          }
        } else {
          value += line[i];
          i++;
        }
      }
      fields.push(value);
      if (i < len && line[i] === delimiter) {
        i++;
        if (i === len) {
          fields.push("");
        }
      }
    } else {
      var nextDelim = line.indexOf(delimiter, i);
      if (nextDelim === -1) {
        fields.push(line.substring(i));
        break;
      } else {
        fields.push(line.substring(i, nextDelim));
        i = nextDelim + 1;
        if (i === len) {
          fields.push("");
        }
      }
    }
  }
  return fields;
}

function splitLogicalLines(input, lineSeparator, quote) {
  var lines = [];
  var current = "";
  var insideQuotes = false;
  var i = 0;
  var len = input.length;
  var sepLen = lineSeparator.length;
  while (i < len) {
    if (input[i] === quote) {
      insideQuotes = !insideQuotes;
      current += input[i];
      i++;
      continue;
    }
    if (!insideQuotes && input.substring(i, i + sepLen) === lineSeparator) {
      lines.push(current);
      current = "";
      i += sepLen;
      continue;
    }
    current += input[i];
    i++;
  }
  if (current.length > 0) {
    lines.push(current);
  }
  return lines;
}

function buildResult(rows, headers, errors) {
  return {
    rows: rows,
    headers: headers,
    errors: errors,
    filter: function(predicate) {
      return rows.filter(predicate);
    },
    sum: function(column) {
      var total = 0;
      for (var ri = 0; ri < rows.length; ri++) {
        var val = rows[ri][column];
        if (typeof val === "number") total += val;
      }
      return total;
    },
    average: function(column) {
      var total = 0;
      var count = 0;
      for (var ri = 0; ri < rows.length; ri++) {
        var val = rows[ri][column];
        if (typeof val === "number") { total += val; count++; }
      }
      return count === 0 ? 0 : total / count;
    },
    count: function() { return rows.length; },
    groupBy: function(column) {
      var map = new Map();
      for (var ri = 0; ri < rows.length; ri++) {
        var key = rows[ri][column];
        if (!map.has(key)) map.set(key, []);
        map.get(key).push(rows[ri]);
      }
      return map;
    }
  };
}

function parseCSV(input, options) {
  var delimiter = (options && options.delimiter != null) ? options.delimiter : ",";
  var quote = (options && options.quote != null) ? options.quote : '"';
  var lineSeparator = (options && options.lineSeparator != null) ? options.lineSeparator : "\n";
  var errors = [];
  var trimmed = input.trim();
  if (trimmed === "") {
    return buildResult([], [], errors);
  }
  var lines = splitLogicalLines(trimmed, lineSeparator, quote);
  if (lines.length === 0) {
    return buildResult([], [], errors);
  }
  var headers = parseRow(lines[0], delimiter, quote);
  var rows = [];
  for (var idx = 1; idx < lines.length; idx++) {
    var line = lines[idx];
    if (line.trim() === "") continue;
    try {
      var fields = parseRow(line, delimiter, quote);
      if (fields.length !== headers.length) {
        errors.push({ row: idx + 1, message: "Expected " + headers.length + " fields but got " + fields.length });
        var row = {};
        for (var c = 0; c < headers.length; c++) {
          row[headers[c]] = c < fields.length ? coerceValue(fields[c]) : null;
        }
        rows.push(row);
        continue;
      }
      var row = {};
      for (var c = 0; c < headers.length; c++) {
        row[headers[c]] = coerceValue(fields[c]);
      }
      rows.push(row);
    } catch (err) {
      var msg = err instanceof Error ? err.message : String(err);
      errors.push({ row: idx + 1, message: "Parse error: " + msg });
    }
  }
  return buildResult(rows, headers, errors);
}

