  assertClose(result.sum("price"), 7.0, 0.001, "sum of prices");
});

test("sum ignores non-numeric values", function() {
  var csv = "val\n10\nhello\n20\nnull";
  var result = parseCSV(csv);
  assertEqual(result.sum("val"), 30, "sum skips non-numbers");
});

test("sum of non-existent column is 0", function() {
  var csv = "a\n1\n2";
