test("average of numeric column", function() {
  var csv = "val\n10\n20\n30";
  var result = parseCSV(csv);
  assertClose(result.average("val"), 20, 0.001, "average");
});

test("average ignores non-numeric values", function() {
  var csv = "val\n10\nhello\n20";
  var result = parseCSV(csv);
  assertClose(result.average("val"), 15, 0.001, "average skips non-numbers");
});

test("average of empty dataset is 0", function() {
  var csv = "val";
  var result = parseCSV(csv);
  assertEqual(result.average("val"), 0, "no data -> 0");
});

test("average of non-existent column is 0", function() {
