test("empty input returns empty result", function() {
  var result = parseCSV("");
  assertEqual(result.headers, [], "no headers");
  assertEqual(result.rows, [], "no rows");
  assertEqual(result.errors, [], "no errors");
  assertEqual(result.count(), 0, "count 0");
});

test("whitespace-only input returns empty result", function() {
  var result = parseCSV("   \n  \n  ");
  assertEqual(result.headers, [], "no headers");
  assertEqual(result.rows, [], "no rows");
});

test("single column CSV", function() {
  var csv = "id\n1\n2\n3";
  var result = parseCSV(csv);
  assertEqual(result.headers, ["id"], "one header");
  assertEqual(result.rows.length, 3, "three rows");
  assertEqual(result.rows[0]["id"], 1, "first value");
});

test("single row (header only)", function() {
  var csv = "a,b,c";
  var result = parseCSV(csv);
  assertEqual(result.headers, ["a", "b", "c"], "headers parsed");
  assertEqual(result.rows.length, 0, "no data rows");
});

test("single data row", function() {
  var csv = "x\n42";
  var result = parseCSV(csv);
  assertEqual(result.rows.length, 1, "one row");
  assertEqual(result.rows[0]["x"], 42, "value");
});

test("very large field", function() {
  var bigValue = "";
  for (var vi = 0; vi < 100000; vi++) bigValue += "x";
  var csv = "col\n" + bigValue;
  var result = parseCSV(csv);
  assertEqual(result.rows[0]["col"], bigValue, "large field preserved");
  assertEqual(result.rows[0]["col"].length, 100000, "correct length");
});

test("many columns", function() {
  var n = 200;
  var hdrs = [];
  var vals = [];
  for (var ci = 0; ci < n; ci++) { hdrs.push("col" + ci); vals.push(String(ci)); }
  var csv = hdrs.join(",") + "\n" + vals.join(",");
  var result = parseCSV(csv);
  assertEqual(result.headers.length, n, "200 headers");
  assertEqual(result.rows[0]["col0"], 0, "first col");
  assertEqual(result.rows[0]["col199"], 199, "last col");
});

test("trailing newline does not create ghost row", function() {
  var csv = "a\n1\n2\n";
  var result = parseCSV(csv);
  assertEqual(result.rows.length, 2, "no ghost row");
});

test("mixed types in one row", function() {
  var csv = "a,b,c,d,e,f\nhello,42,true,null,3.14,";
  var result = parseCSV(csv);
  var row = result.rows[0];
  assertEqual(row["a"], "hello", "string");
  assertEqual(row["b"], 42, "int");
  assertEqual(row["c"], true, "bool");
  assertEqual(row["d"], null, "null literal");
  assertClose(row["e"], 3.14, 0.001, "float");
  assertEqual(row["f"], null, "empty -> null");
});

test("quoted field containing only quote characters", function() {
  var csv = 'a\n""""';
  var result = parseCSV(csv);
  assertEqual(result.rows[0]["a"], '"', "single quote");
});

test("combination: custom delimiter + quotes + type coercion", function() {
  var csv = 'name;score;active\n"Alice";95.5;true\n"Bob";87;false';
  var result = parseCSV(csv, { delimiter: ";" });
  assertEqual(result.rows[0]["name"], "Alice", "quoted name");
  assertClose(result.rows[0]["score"], 95.5, 0.001, "float score");
  assertEqual(result.rows[0]["active"], true, "boolean");
  assertEqual(result.rows[1]["score"], 87, "int score");
  assertEqual(result.rows[1]["active"], false, "boolean false");
});

test("filter + aggregation combo", function() {
  var csv = "dept,salary\nEng,100\nSales,80\nEng,120\nSales,90\nEng,110";
  var result = parseCSV(csv);
  var engRows = result.filter(function(r) { return r.dept === "Eng"; });
  assertEqual(engRows.length, 3, "3 engineers");
  var engSum = 0;
  for (var si = 0; si < engRows.length; si++) engSum += engRows[si].salary;
  assertEqual(engSum, 330, "eng salary sum");
});

test("empty fields between delimiters", function() {
  var csv = "a,b,c\n,,\n1,,3";
  var result = parseCSV(csv);
  assertEqual(result.rows[0], { a: null, b: null, c: null }, "all empty -> null");
  assertEqual(result.rows[1], { a: 1, b: null, c: 3 }, "middle empty");
});

test("header with quotes", function() {
  var csv = '"First Name","Last Name"\nJohn,Doe';
  var result = parseCSV(csv);
  assertEqual(result.headers, ["First Name", "Last Name"], "quoted headers");
  assertEqual(result.rows[0]["First Name"], "John", "value by quoted header");
});

test("unicode content", function() {
  var csv = "name,emoji\nTöm,🎉\nSaké,🍶";
  var result = parseCSV(csv);
  assertEqual(result.rows[0]["name"], "Töm", "unicode chars");
  assertEqual(result.rows[0]["emoji"], "🎉", "emoji");
  assertEqual(result.rows[1]["name"], "Saké", "accented");
});

test("CRLF line endings with quoted fields containing LF", function() {
  var csv = 'a,b\r\n"line1\nline2",val\r\nnext,row';
  var result = parseCSV(csv, { lineSeparator: "\r\n" });
  assertEqual(result.rows.length, 2, "two data rows");
  assertEqual(result.rows[0]["a"], "line1\nline2", "LF inside CRLF file");
  assertEqual(result.rows[1]["a"], "next", "row after multiline");
});

